// ============================================================
// NODE: Validate & Normalize Input
// Ensures all inbound prospects have the minimum required fields
// before we spend credits on enrichment.
// ============================================================

const items = $input.all();
const validated = [];
const rejected = [];

for (const item of items) {
  const d = item.json;

  // --- Minimum required fields ---
  const companyName = (d.company_name || d.companyName || d.Company || '').trim();
  const contactEmail = (d.contact_email || d.email || d.Email || '').trim();
  const contactName  = (d.contact_name || d.name || d.Name || d.full_name || '').trim();
  const contactTitle = (d.contact_title || d.title || d.Title || d.job_title || '').trim();
  const domain       = (d.domain || d.website || d.Website || '').trim();

  // Derive domain from email if not provided
  const derivedDomain = domain || (contactEmail.includes('@') ? contactEmail.split('@')[1] : '');

  if (!companyName && !derivedDomain) {
    rejected.push({
      json: { ...d, _reject_reason: 'Missing both company_name and domain — cannot enrich' }
    });
    continue;
  }

  validated.push({
    json: {
      company_name: companyName,
      contact_name: contactName,
      contact_title: contactTitle,
      contact_email: contactEmail,
      domain: derivedDomain,
      country: (d.country || d.Country || '').trim(),
      // Pass through any extra fields under _raw
      _raw: d
    }
  });
}

// Output 0 = validated prospects, Output 1 = rejected
return [validated, rejected];

// ============================================================
// NODE: Merge Enrichment Results
// Combines the parallel enrichment API responses back into
// a single unified prospect record.
//
// VERIFIED FIELD MAPPINGS (from LeadMagic docs 2026-03-17):
//   Company Search → companyName, employeeCount, industry,
//     description, tagline, websiteUrl, headquarter, revenue,
//     revenue_formatted, employee_range, total_funding,
//     last_funding_round, last_funding_amount, last_funding_date,
//     b2b_profile_url, competitors
//   Email Finder → email, status, employment_verified,
//     mx_provider, company_name, company_industry, company_size
//   Company Funding → (separate detailed funding endpoint)
// ============================================================

const original   = $('Validate & Normalize').item.json;
const company    = $('LeadMagic: Company Enrich').item.json;
const emailData  = $('LeadMagic: Email Find').item.json;
const funding    = $('LeadMagic: Funding Data').item.json;

// --- Safely extract company enrichment fields ---
const enriched = {
  // Original fields
  company_name:      original.company_name || company.companyName || '',
  contact_name:      original.contact_name,
  contact_title:     original.contact_title,
  domain:            original.domain,
  country:           original.country || (company.headquarter ? company.headquarter.country : '') || '',

  // Email enrichment (verified field names from LeadMagic Email Finder)
  contact_email:     emailData.email || original.contact_email || '',
  email_status:      emailData.status || null,
  email_verified:    emailData.employment_verified || false,
  mx_provider:       emailData.mx_provider || null,

  // Company enrichment (verified field names from LeadMagic Company Search)
  company_description: company.description || company.tagline || '',
  employee_count:      company.employeeCount || null,
  employee_range:      company.employee_range || (company.employeeCountRange ? `${company.employeeCountRange.start}-${company.employeeCountRange.end}` : '') || '',
  industry:            company.industry || emailData.company_industry || '',
  subindustry:         '',
  estimated_revenue:   company.revenue_formatted || (company.revenue ? String(company.revenue) : '') || '',
  linkedin_url:        company.b2b_profile_url ? `https://linkedin.com/company/${company.b2b_profile_url}` : '',
  website:             company.websiteUrl || original.domain,
  ownership_status:    company.ownership_status || '',
  founded_year:        company.founded_year || (company.foundedOn ? company.foundedOn.year : null) || null,
  competitors:         company.competitors || [],

  // Funding (from Company Search + dedicated Funding endpoint)
  total_funding:       company.total_funding || funding.total_funding || null,
  last_funding_date:   company.last_funding_date || funding.last_funding_date || null,
  last_funding_amount: company.last_funding_amount || funding.last_funding_amount || null,
  funding_stage:       company.last_funding_round || funding.last_funding_round || '',
  funding_rounds:      company.funding_rounds || funding.funding_rounds || null,

  // Business type — will be classified in next node
  business_type: null,

  // Metadata
  enriched_at:        new Date().toISOString(),
  enrichment_source:  'leadmagic',
  enrichment_status:  company.message === 'Company found' ? 'complete' : 'partial',
  credits_consumed:   (company.credits_consumed || 0) + (emailData.credits_consumed || 0) + (funding.credits_consumed || 0)
};

return { json: enriched };

// ============================================================
// NODE: Classify B2B / B2C
// If LeadMagic didn't return business_type, use a simple
// heuristic. For production, swap this for an LLM call.
// ============================================================

const p = $input.item.json;

let businessType = p.business_type;

if (!businessType) {
  // Heuristic classification based on industry + description
  const desc = (p.company_description || '').toLowerCase();
  const industry = (p.industry || '').toLowerCase();

  const b2bSignals = [
    'enterprise', 'saas', 'b2b', 'platform', 'api', 'infrastructure',
    'software', 'solutions', 'services', 'consulting', 'analytics',
    'automation', 'workforce', 'compliance', 'fintech', 'devops',
    'cybersecurity', 'data', 'cloud', 'procurement'
  ];

  const b2cSignals = [
    'consumer', 'b2c', 'retail', 'ecommerce', 'e-commerce',
    'marketplace', 'app', 'gaming', 'entertainment', 'food',
    'fashion', 'fitness', 'health', 'beauty', 'travel'
  ];

  const text = `${desc} ${industry}`;
  const b2bScore = b2bSignals.filter(s => text.includes(s)).length;
  const b2cScore = b2cSignals.filter(s => text.includes(s)).length;

  if (b2bScore > b2cScore) businessType = 'B2B';
  else if (b2cScore > b2bScore) businessType = 'B2C';
  else businessType = 'B2B2C'; // ambiguous — flag for manual review
}

return {
  json: {
    ...p,
    business_type: businessType
  }
};

// ============================================================
// NODE: Qualify Prospect
// Applies Exprs ICP must-have and disqualifier rules.
// Output 0 = Qualified, Output 1 = Disqualified
// ============================================================

const p = $input.item.json;

// --- ICP Must-Haves ---
const empCount = parseInt(p.employee_count) || 0;
const employeeQualified = empCount >= 20 && empCount <= 200;
const isB2B = ['B2B', 'B2B2C'].includes(p.business_type);

// --- Disqualifiers ---
const tooSmall = empCount > 0 && empCount < 20;
const tooLarge = empCount > 200;
const noData   = empCount === 0; // enrichment returned nothing

let qualification = 'disqualified';
let disqualify_reason = null;

if (noData) {
  disqualify_reason = 'Employee count unknown — enrichment incomplete';
  qualification = 'review'; // send to manual review, don't auto-disqualify
} else if (tooSmall) {
  disqualify_reason = 'Under 20 employees — too early for recruitment infrastructure';
} else if (tooLarge) {
  disqualify_reason = 'Over 200 employees — likely has internal TA function';
} else if (!isB2B) {
  disqualify_reason = `Business type is ${p.business_type} — ICP requires B2B`;
} else if (employeeQualified && isB2B) {
  qualification = 'must_have';
}

const result = {
  json: {
    ...p,
    qualified: qualification === 'must_have',
    qualification,
    disqualify_reason,
    // Default fields for later pipeline stages
    signals: {},
    score: qualification === 'must_have' ? 'must_have' : null,
    message_route: null,
    creative_ideas: null,
    smartlead_campaign_id: null,
    sent_at: null
  }
};

if (qualification === 'must_have') {
  return [result, []];
} else {
  return [[], result];
}
